let faultCount = Number(p.fault_count || 0);
let missingFields = (p.missing_fields || "").trim();

// robust fault check
let hasFault =
    p.system_fault == 1 ||
    faultCount > 0 ||
    Object.keys(faults).length > 0 ||
    missingFields !== "";

// read comm watchdog state
let commFault = flow.get("arduino_comm_fault") || 0;

let log = flow.get("fault_log") || [];
let lastSig = flow.get("fault_log_last_sig") || "";
let lastState = flow.get("fault_log_last_state") || "normal";

// timestamp
let ts = p.ts || p.ts_ms || Date.now();
let d = new Date(ts);

function pad(n) {
    return String(n).padStart(2, "0");
}

let stamp =
    (d.getMonth() + 1) + "/" +
    d.getDate() + "/" +
    d.getFullYear() + " " +
    pad(d.getHours()) + ":" +
    pad(d.getMinutes()) + ":" +
    pad(d.getSeconds());

// Build list of faults exactly like fault text logic
let faultList = [];

// Add sensor / payload faults
let keys = Object.keys(faults).sort();
if (keys.length) {
    faultList = faultList.concat(
        keys.map(function (k) {
            return k + ": " + faults[k];
        })
    );
} else if (missingFields !== "") {
    faultList.push("Missing fields: " + missingFields);
} else if (hasFault && commFault !== 1) {
    faultList.push("FAULT ACTIVE");
}

