    if (faultList.length > 0) {
        log.unshift("🔴 [" + stamp + "] " + faultText);
        lastState = "fault";
    } else {
        if (lastState === "fault") {
            log.unshift("🟢 [" + stamp + "] All Systems Normal");
        }
        lastState = "normal";
    }

    // Keep newest 100 entries
    if (log.length > 100) {
        log = log.slice(0, 100);
    }

    flow.set("fault_log", log);
    flow.set("fault_log_last_sig", sig);
    flow.set("fault_log_last_state", lastState);
}

